UPDATE STOCIVHD SET
    INV_DATE = #{INV_DATE}
    , PIC_USER_ID = #{ses.userId}
    , PIC_USER_NM = #{ses.userNm}
    , PIC_TEL_NUM = #{ses.telNum}
    , PIC_CELL_NUM = #{ses.cellNum}
    , PROGRESS_CD = #{PROGRESS_CD}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD = #{ses.gateCd}
AND BUYER_CD = #{BUYER_CD}
AND INV_NUM = #{INV_NUM}

mapper.select:
SELECT IVGH.INV_NUM AS INV_NUM , IVHD.VENDOR_CD AS VENDOR_CD , GETCOMPANYNAME(POHD.GATE_CD, POHD.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , IVGH.VENDOR_USER_NM AS PIC_USER_NM , IVGH.VENDOR_TEL_NUM AS PIC_TEL_NUM , IVGH.VENDOR_CELL_NUM AS PIC_CELL_NUM , IVHD.CUR AS CUR , IVHD.VAT_TYPE AS VAT_TYPE , POHD.PO_CREATE_TYPE , (POHD.PO_CREATE_DATE, 'YYYY-MM-DD') AS PO_CREATE_DATE , POHD.PO_NUM AS PO_NUM , POHD.CTRL_USER_ID AS CTRL_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , POHD.INSPECT_USER_ID AS INSPECT_USER_ID , GETUSERNAME(POHD.GATE_CD, POHD.INSPECT_USER_ID, #{ses.langCd}) AS INSPECT_USER_NM , POHD.PAY_TERMS AS PAY_TERMS , POHD.PO_AMT AS PO_AMT , IVHD.BUYER_CD AS BUYER_CD , IVHD.DEPT_CD , IVHD.INV_AMT , IVHD.VAT_AMT , IVGH.RMK_TEXT_NUM , IVGH.ATT_FILE_NUM , IVHD.ATT_FILE_NUM2 AS C_ATT_FILE_NUM , (IVGH.SEND_DATE, 'YYYY-MM-DD') AS SEND_DATE , (IVGH.INV_SEND_DATE, 'YYYY-MM-DD') AS INV_SEND_DATE , IVGH.SUBJECT , IVHD.GUAR_TYPE , IVHD.GUAR_PERCENT , IVHD.GUAR_QT , IVHD.VAT_FLAG , IVHD.GUAR_AMT , IVHD.GUAR_TYPE2 , IVHD.GUARANTEER , IVHD.ATT_FILE_NUM AS GUAR_ATT_FILE_NUM , IVHD.RMK , IVHD.INSU_STATUS , IVHD.GUAR_NUM , IVHD.APP_DOC_NUM , IVHD.APP_DOC_CNT , IVHD.PROGRESS_CD ,(CASE WHEN IVHD.SIGN_STATUS IN ('T', 'P', 'R', 'C') THEN GETCOMCODE(IVHD.GATE_CD, 'M020', IVHD.SIGN_STATUS, 0, 'KO') ELSE GETCOMCODE(IVHD.GATE_CD, 'M101', IVHD.PROGRESS_CD, 0, 'KO') END) AS PROGRESS_CD_LOC , IVHD.SIGN_STATUS , IVHD.INV_DATE , (IVHD.REG_DATE, 'YYYY-MM-DD') AS REG_DATE , (GRDT.GR_DATE, 'YYYY-MM-DD') AS GR_DATE , IVGH.PAY_CNT , IVGH.REJECT_RMK , IVHD.DELIVERY_TYPE ,(SELECT MAX(SIGN_STATUS) FROM STOCIVAP WHERE GATE_CD = IVGH.GATE_CD AND BUYER_CD = IVGH.BUYER_CD AND INV_NUM = IVGH.INV_NUM AND PAY_CNT = IVGH.PAY_CNT) AS AP_STATUS -- 해당 검수요청서로 등록된 대금지급요청서 진행상태 FROM STOCIVGH IVGH LEFT JOIN STOCIVHD IVHD ON (IVHD.GATE_CD = IVGH.GATE_CD AND IVHD.BUYER_CD = IVGH.BUYER_CD AND IVHD.INV_NUM = IVGH.INV_NUM AND IVHD.DEL_FLAG = '0') LEFT JOIN STOCPOHD POHD ON (POHD.GATE_CD = IVGH.GATE_CD AND POHD.BUYER_CD = IVGH.BUYER_CD AND POHD.PO_NUM = IVGH.PO_NUM AND POHD.DEL_FLAG = '0') LEFT JOIN STOCGRDT GRDT ON (GRDT.GATE_CD = IVHD.GATE_CD AND GRDT.BUYER_CD = IVHD.BUYER_CD AND GRDT.INV_NUM = IVHD.INV_NUM AND GRDT.DEL_FLAG = '0' AND GRDT.GR_SQ = '1') WHERE IVGH.GATE_CD = #{ses.gateCd} AND POHD.BUYER_CD = #{BUYER_CD}
AND IVGH.INV_NUM = #{INV_NUM}
AND IVHD.APP_DOC_NUM = #{APP_DOC_NUM}

